-- ============================================================================
-- SYNTHETIC seed data for the local biskfarm_report_pp3 test double.
--
-- Builds a 6-level sales-force org tree (VP -> ZSM -> RSM -> BM -> ASM -> SO)
-- and 4 geographic branches (Trichy/Tamilnadu, Chennai/Tamilnadu, Kochi/Kerala,
-- Durgapur/West Bengal) so RBAC-scoped queries return different, non-empty,
-- properly nested slices for each of the 6 seeded users (scripts/seed_users.py):
--   - so  (geo_hier7_name='Trichy Town')             -> smallest slice
--   - asm (geo_hier6_name='CHENNAI District')        -> Chennai-only slice (sibling of Trichy under the same BM)
--   - bm  (geo_hier4_name='TAMILNADU STATE')          -> Trichy + Chennai
--   - rsm (geo_hier3_name='REGION 6')                 -> same as bm's branch (Region 6 = Tamilnadu)
--   - zsm (geo_hier2_name='SOUTH')                     -> Trichy + Chennai + Kochi (Region 5 = Kerala)
--   - vp  (unrestricted)                               -> everything, incl. Durgapur/East (vp-only)
--
-- Fact rows are dated CURDATE(), CURDATE()-1 day, and ~1 month back so
-- temporal ("today" / "this month" / "yesterday") questions differ.
-- ============================================================================

USE biskfarm_report_pp3;

